const searchResults = $input.item.json.organic || [];
const keyword = $input.item.json.keyword || $('Loop Over Keywords').item.json.keyword;
const country = $input.item.json.country || $('Loop Over Keywords').item.json.country;

const excludedDomains = [
  'reddit.com', 'facebook.com', 'instagram.com',
  'twitter.com', 'x.com', 'tiktok.com', 'pinterest.com',
  'youtube.com', 'linkedin.com'
];

function shouldExclude(url) {
  const lowerUrl = (url || '').toLowerCase();
  return excludedDomains.some(domain => lowerUrl.includes(domain));
}

const cleanResults = [];
for (const result of searchResults) {
  if (!result.link) continue;
  if (shouldExclude(result.link)) continue;

  cleanResults.push({
    title: result.title || '',
    link: result.link || '',
    snippet: result.snippet || '',
    position: result.position || 0
  });

  if (cleanResults.length >= 10) break;
}

return {
  json: {
    filtered_results: cleanResults,
    keyword,
    country
  }
};

const filteredResults = $input.item.json.filtered_results || [];
const keyword = $input.item.json.keyword;
const country = $input.item.json.country;

const promptText = `SEARCH RESULTS:

${JSON.stringify(filteredResults, null, 2)}

KEYWORD: ${keyword}
COUNTRY / REGION: ${country || 'Not specified'}

TASK: From the search results above, select the best 5 URLs that would provide the most comprehensive information for creating a content brief about '${keyword}'.

Exclude any URLs that:
- Cannot be scraped reliably
- Are from social media, forums, or profile pages
- Are too general or not specific to the keyword

Prioritize pages that clearly match the query intent and target location if a country/region is provided.

Return ONLY a JSON array with this exact structure:
[
  {"title": "...", "link": "...", "snippet": "..."},
  {"title": "...", "link": "...", "snippet": "..."}
]

No other text or explanation. Just the JSON array.`;

return {
  json: {
    geminiPayload: {
      contents: [{ parts: [{ text: promptText }] }],
      generationConfig: {
        temperature: 0.1,
        maxOutputTokens: 8192
      }
    },
    keyword,
    country,
    filtered_results: filteredResults
  }
};

const geminiResponse = $input.item.json;
let contentText = '';

if (geminiResponse.candidates && geminiResponse.candidates[0]) {
  const parts = geminiResponse.candidates[0].content.parts;
  if (parts && parts[0]) {
    contentText = parts[0].text || '';
  }
}

contentText = contentText.replace(/\`\`\`json/g, '').replace(/\`\`\`/g, '').trim();

function extractJsonArray(text) {
  const start = text.indexOf('[');
  const end = text.lastIndexOf(']');
  if (start === -1 || end === -1) return [];
  try {
    return JSON.parse(text.substring(start, end + 1));
  } catch (e) {
    console.error('Failed to parse JSON:', e);
    return [];
  }
}

const previous = $('Prepare Gemini Request').item.json;
const urls = extractJsonArray(contentText);

return {
  json: {
    urls: urls.length ? urls.slice(0, 5) : (previous.filtered_results || []).slice(0, 5),
    keyword: previous.keyword,
    country: previous.country,
    filtered_results: previous.filtered_results || []
  }
};

