const allItems = $input.all();
const upstream = $('Extract URLs').item.json;
const keyword = upstream.keyword;
const country = upstream.country;

const summaries = allItems.map(item => {
  if (item.json.candidates && item.json.candidates[0]) {
    const parts = item.json.candidates[0].content.parts;
    if (parts && parts[0]) {
      return parts[0].text;
    }
  }
  return '';
}).filter(Boolean);

function extractListCount(text) {
  const match = text.match(/\b(?:top|best|leading)\s+(\d{1,2})\b/i) || text.match(/\b(\d{1,2})\s+(?:best|top)\b/i);
  return match ? Number(match[1]) : null;
}

const lowerKeyword = (keyword || '').toLowerCase();
const listCount = extractListCount(lowerKeyword);
const isComparison = /\b(vs|versus|compare|comparison)\b/i.test(lowerKeyword);
const isListicle = /\b(best|top|list|ideas|examples|types)\b/i.test(lowerKeyword) || Boolean(listCount);
const isLocal = /\b(in|near|around)\b/i.test(lowerKeyword) || Boolean(country);
const isHowTo = /\b(how to|guide|tips|ways|what is)\b/i.test(lowerKeyword);
const isHospitality = /\b(hotel|hotels|restaurant|restaurants|cafe|cafes|coffee shop|coffee shops|resort|resorts|bar|bars)\b/i.test(lowerKeyword);
const isCommercial = /\b(price|pricing|cost|buy|service|agency|company|software|tool|tools|platform)\b/i.test(lowerKeyword);

let keywordType = 'informational';
let articleFormat = 'guide';
let inferredIntent = 'informational';

if (isComparison) {
  keywordType = 'comparison';
  articleFormat = 'comparison page';
  inferredIntent = 'commercial investigation';
} else if (isListicle && isLocal && isHospitality) {
  keywordType = 'localized ranked list';
  articleFormat = 'ranked local listicle';
  inferredIntent = 'local commercial investigation';
} else if (isListicle) {
  keywordType = 'ranked list';
  articleFormat = 'listicle';
  inferredIntent = isCommercial ? 'commercial investigation' : 'informational';
} else if (isHowTo) {
  keywordType = 'how-to';
  articleFormat = 'step-by-step guide';
  inferredIntent = 'informational';
} else if (isCommercial) {
  keywordType = 'commercial page';
  articleFormat = 'buyer guide';
  inferredIntent = 'commercial investigation';
}

const competitor_analysis = summaries.join('\n\n---\n\n');

return {
  keyword,
  country,
  competitor_analysis,
  num_competitors: summaries.length,
  keyword_signals: {
    keywordType,
    articleFormat,
    inferredIntent,
    listCount,
    isLocal,
    isHospitality,
    isCommercial,
    isComparison,
    isHowTo,
    filteredResults: upstream.filtered_results || []
  }
};

const geminiResponse = $input.item.json;
let briefContent = '';

if (geminiResponse.candidates && geminiResponse.candidates[0]) {
  const parts = geminiResponse.candidates[0].content.parts;
  if (parts && parts[0]) {
    briefContent = parts[0].text;
  }
}

const upstream = $('Combine Summaries').item.json;
const keyword = upstream.keyword;
const country = upstream.country;

if (!keyword) {
  return {
    filename: 'brief_unknown.txt',
    keyword: 'unknown',
    country,
    brief_content: briefContent,
    timestamp: new Date().toISOString()
  };
}

const filename = `brief_${keyword.replace(/\s+/g, '_')}.txt`;
const timestamp = new Date().toISOString();
const finalBrief = `${briefContent}\n\n---\nGenerated: ${timestamp}\n`;

return {
  filename,
  keyword,
  country,
  brief_content: finalBrief,
  timestamp
};

const allItems = $input.all();

const briefs = allItems.map(item => ({
  keyword: item.json.keyword,
  country: item.json.country,
  filename: item.json.filename,
  brief_content: item.json.brief_content,
  timestamp: item.json.timestamp
}));

return briefs.map(brief => ({
  json: brief,
  binary: {
    data: {
      data: Buffer.from(brief.brief_content).toString('base64'),
      mimeType: 'text/plain',
      fileName: brief.filename
    }
  }
}));
